<?php require_once __DIR__ . '/../includes/config.php'; require_once __DIR__ . '/../includes/db.php'; require_once __DIR__ . '/../includes/functions.php'; require_once __DIR__ . '/../includes/header.php'; require_role(['student']);
if($_SERVER['REQUEST_METHOD']==='POST'){verify_csrf();$course=(int)$_POST['course_id'];$stmt=db()->prepare('INSERT IGNORE INTO registrations(student_id,course_id,status) VALUES(?, ?, "pending")');$stmt->execute([$_SESSION['user']['id'],$course]);}
$courses=db()->query('SELECT id,code,title,unit FROM courses ORDER BY code')->fetchAll(); ?>
<div class="container"><div class="card"><h2>Course Registration</h2><form method="POST"><input type="hidden" name="csrf_token" value="<?= esc(csrf_token()) ?>"><select name="course_id"><?php foreach($courses as $c): ?><option value="<?= $c['id'] ?>"><?= esc($c['code'].' - '.$c['title']) ?></option><?php endforeach; ?></select><button>Register</button></form></div></div><?php require_once __DIR__ . '/../includes/footer.php'; ?>
